var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女と共にいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"이런 자리는 간만이네요, 사장님.","JPN":"こんなことは久しぶりですね、社長。","ENG":"It's been a while since we've had an occasion like this, Boss.","TWN":"老闆好，久違咧，這種場合。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"후후- 다른 호칭으로 부를 수도 있겠지만, 전 이쪽이 편해서요.","JPN":"ふふ……別の呼び方でもいいのですが、私がこっちの方がいいです。","ENG":"Haha. I know I can call you something else, but this feels comfortable.","TWN":"呵呵，我知道我可以換其他叫法，但我比較習慣這麼稱呼老闆。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"세상사람들이 다 아는 그런 흔한 이름으로 부르기보단, 사장님 쪽이 더 저만의 사람 같은 느낌이 든달까요?","JPN":"世界のみんなが知っているありふれた名前で呼ぶより、社長の方が私だけの人って感じがしますからね。","ENG":"Instead of using a common name that everyone knows, calling you as Boss makes it feel like you're someone special to me.","TWN":"我不喜歡跟大家一樣，叫你老闆，有種你是我的人的感覺。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"사장님도 그렇게 생각하시죠?","JPN":"社長もそう思うでしょう？","ENG":"You think that way too, Boss, right?","TWN":"老闆也是這麼想的吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"사실 정식 라이선스를 따낸 뒤에도 이곳에 남는 건 저희 계획이 아니었어요.","JPN":"実は、正式ライセンスを取った後にもここに残るのは私たちの計画ではなかったのです。","ENG":"Honestly, staying here even after getting the official license wasn't part of our plan.","TWN":"其實獲得正式授權後，我們原本不打算繼續留在這裡的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"늘 살아남는 걸 최우선으로 생각해왔으니까. 이런 위험한 일을 하는 회사에 남을 이유도 없죠.","JPN":"いつも生き残ることを最優先としてきましたから。こんな危険な仕事をする会社に残る理由もありません。","ENG":"I've always prioritized survival above all else. There's no reason to stay in a company that does such dangerous work.","TWN":"畢竟生存一直是我們最優先的考量，所以沒理由留在這種從事危險工作的公司。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"하지만 걱정 마세요. 이런 계약이 아니라도 알트 소대는 계속 코핀 컴퍼니에 남을 테니까.","JPN":"でも、心配しないでください。こんな契約でなくてもアルト小隊はずっとコフィンカンパニーに残ります。","ENG":"But don't worry. Regardless of this contract, ALT Squad will continue to stay under Coffin Company.","TWN":"但請放心，就算不是因為這份契約，阿爾特小隊還是會繼續留在科芬公司的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"이유를 물으셔도 제가 똑 부러지게 답할 자신은 없네요. 단순한 여자의 변덕 같은 거라서요.","JPN":"理由を聞かれましてもはっきりと答える自信はありませんね。単なる女の気まぐれみたいなものですから。","ENG":"Even if you ask me why, I'm not confident I can give you a clear answer. It's just a simple whim of a woman.","TWN":"如果你要問理由，老實說，我也沒辦法給出一個明確的答案。我只能說女人是多變的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"제가 사장님 덕분에 바라던 걸 이뤘으니, 이젠 사장님이 잘 되는 모습을 보고 싶어졌달까요?","JPN":"私が社長のおかげで望みを叶えましたから、あとは社長が成功する姿が見たくなったというか。","ENG":"Since I've achieved what I wanted thanks to you, Boss, I guess now I want to see you doing well.","TWN":"因為有老闆，我才能實現夢想。所以現在我也希望能夠看到老闆過得好。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"물론 저희가 넘어야 했던 시련에 비하면 그 길이 얼마나 더 고될 지 전 모르지만요.","JPN":"もちろん私たちが越えなければならなかった試練に比べて、それがどれほど厳しい道になるかはわかりませんけど。","ENG":"Of course, I don't know how much harder that path will be compared to the trials we've already overcome.","TWN":"當然，跟我們曾經歷的那些試煉相比，我無法預測這條路究竟還會有多少艱辛。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"어쩌면 엄청 수지에 맞지 않는 고난의 연속이 기다리고 있겠죠.","JPN":"もしかしたら、とても引き合わない苦難の連続が待っているかもしれません。","ENG":"Perhaps an endless series of incredibly unrewarding hardships awaits.","TWN":"也許等待我們的只是接連不斷、毫無回報的困難。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"그래도 상관없어요.","JPN":"それでも構いませんよ。","ENG":"It still doesn't matter.","TWN":"但沒關係。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"우리에게 희망을 가져다 준 사람이… 머물지 않고 어딜 향해 가는지.","JPN":"私たちに希望をもたらしてくれた人が……止まらず、どこに向かっているのか。","ENG":"Where is the one who brought us hope... headed without settling down?","TWN":"因為那個曾為我們帶來希望的人…不會停滯不前。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"이 회사의 비전 끝에 뭐가 있을지- 이젠 궁금해서 못 참겠거든요.","JPN":"この会社の進む先には何があるのかーもう気になって仕方がありません。","ENG":"What awaits at the end of this company's future? I just can't contain my curiosity anymore.","TWN":"而且我現在非常好其，他要往哪裡去？這間公司的願景，最終又會通往何方？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};